mapper.select:
SELECT 
  FROM wallet_address WHERE merchant_id = #{merchantId}
 ORDER BY created_at DESC

mapper.update:
UPDATE deposit
   SET status        = #{status},
       confirmations = #{confirmations},
       ledger_tx_id  = #{ledgerTxId},
       credited_at   = #{creditedAt}
 WHERE id = #{id}

mapper.select:
SELECT 
  FROM deposit WHERE status IN ('DETECTED', 'CONFIRMING')
 ORDER BY detected_at ASC LIMIT #{limit}

SELECT 
  FROM withdrawal WHERE merchant_id = #{merchantId} AND id = #{id}
   FOR UPDATE

SELECT 
  FROM withdrawal WHERE merchant_id = #{merchantId}
 AND status = #{status} 
 ORDER BY requested_at DESC LIMIT #{limit}

SELECT 
  FROM withdrawal WHERE status IN ('SUBMITTED', 'CONFIRMING')
 ORDER BY submitted_at ASC NULLS LAST LIMIT #{limit}
